// Clear the Turbopack persistent cache before every build.
//
// Vercel restores .next/cache from the PREVIOUS deployment. Turbopack's
// persistent cache can then mix stale compiled chunks into the new output:
// externalised server packages are required via hash-aliased ids (e.g.
// require("@prisma/extension-accelerate-<hash>")) that must match the symlinks
// in .next/node_modules generated by the SAME build. A restored cache from a
// build with different hashes (e.g. after a next.config change, or the
// turbopack.root fix) leaves chunks requiring old ids that have no symlink →
// "Failed to load external module …: Cannot find module" → 500s in production.
//
// Cost: roughly a minute of extra compile time per deploy. Worth it until
// Turbopack's cache invalidation can be trusted across config changes.
import fs from 'node:fs';

try {
  fs.rmSync('.next/cache', { recursive: true, force: true });
  console.log('[clean-build-cache] cleared .next/cache (Turbopack persistent cache)');
} catch (err) {
  console.warn('[clean-build-cache] could not clear .next/cache:', err?.message || err);
}
